import { Component, EventEmitter, Input, Output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { SchedulingResult } from '../../models/scheduling.model';
import { Process } from '../../models/process.model';

@Component({
  selector: 'app-animation-controls',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './animation-controls.component.html',
  styleUrl: './animation-controls.component.scss'
})
export class AnimationControlsComponent {
  @Input() totalTime: number = 0;
  @Input() currentTime: number = 0;
  @Input() isPlaying: boolean = false;
  @Input() speed: number = 1;
  @Input() mode: 'instant' | 'animation' = 'animation';

  @Output() modeChange = new EventEmitter<'instant' | 'animation'>();
  @Output() play = new EventEmitter<void>();
  @Output() pause = new EventEmitter<void>();
  @Output() stepForward = new EventEmitter<void>();
  @Output() stepBackward = new EventEmitter<void>();
  @Output() reset = new EventEmitter<void>();
  @Output() seekTo = new EventEmitter<number>();
  @Output() speedChange = new EventEmitter<number>();

  speedOptions: number[] = [0.5, 1, 2, 4, 8];

  onModeChange(value: 'instant' | 'animation'): void {
    this.modeChange.emit(value);
  }

  onPlayPause(): void {
    if (this.isPlaying) {
      this.pause.emit();
    } else {
      this.play.emit();
    }
  }

  onStepBackward(): void {
    this.stepBackward.emit();
  }

  onStepForward(): void {
    this.stepForward.emit();
  }

  onReset(): void {
    this.reset.emit();
  }

  onSeekTo(event: Event): void {
    const target = event.target as HTMLInputElement;
    const value = parseFloat(target.value);
    this.seekTo.emit(value);
  }

  onSpeedChange(value: number): void {
    this.speedChange.emit(value);
  }
}
<div class="animation-controls">
  <div class="mode-switch">
    <label class="mode-label">播放模式：</label>
    <div class="radio-group">
      <label class="radio-option">
        <input
          type="radio"
          name="mode"
          value="instant"
          [checked]="mode === 'instant'"
          (change)="onModeChange('instant')"
        />
        <span>一步到位</span>
      </label>
      <label class="radio-option">
        <input
          type="radio"
          name="mode"
          value="animation"
          [checked]="mode === 'animation'"
          (change)="onModeChange('animation')"
        />
        <span>逐步动画</span>
      </label>
    </div>
  </div>

  <div class="controls-row" *ngIf="mode === 'animation'">
    <div class="control-buttons">
      <button
        class="control-btn"
        (click)="onReset()"
        [disabled]="totalTime === 0 || currentTime === 0"
        title="重置"
      >
        <span class="btn-icon">|&lt;</span>
      </button>
      <button
        class="control-btn"
        (click)="onStepBackward()"
        [disabled]="totalTime === 0 || currentTime <= 0 || isPlaying"
        title="后退一步"
      >
        <span class="btn-icon">&lt;&lt;</span>
      </button>
      <button
        class="control-btn play-btn"
        (click)="onPlayPause()"
        [disabled]="totalTime === 0 || currentTime >= totalTime"
        [class.playing]="isPlaying"
        title="{{ isPlaying ? '暂停' : '播放' }}"
      >
        <span class="btn-icon" *ngIf="!isPlaying">▶</span>
        <span class="btn-icon" *ngIf="isPlaying">⏸</span>
      </button>
      <button
        class="control-btn"
        (click)="onStepForward()"
        [disabled]="totalTime === 0 || currentTime >= totalTime || isPlaying"
        title="前进一步"
      >
        <span class="btn-icon">&gt;&gt;</span>
      </button>
    </div>

    <div class="time-display">
      <span class="current-time">{{ currentTime }}</span>
      <span class="time-separator">/</span>
      <span class="total-time">{{ totalTime }}</span>
    </div>
  </div>

  <div class="slider-row">
    <span class="slider-label">时刻</span>
    <input
      type="range"
      class="progress-slider"
      [min]="0"
      [max]="totalTime || 0"
      [value]="currentTime"
      (input)="onSeekTo($event)"
      [disabled]="totalTime === 0"
    />
    <span class="slider-value">{{ currentTime }}</span>
  </div>

  <div class="speed-control">
    <label class="speed-label">播放速度：</label>
    <div class="speed-buttons">
      <button
        *ngFor="let speedOption of speedOptions"
        class="speed-btn"
        [class.active]="speed === speedOption"
        [disabled]="mode !== 'animation'"
        (click)="onSpeedChange(speedOption)"
      >
        {{ speedOption }}x
      </button>
    </div>
  </div>

  <div class="time-display-bottom">
    时刻 {{ currentTime }} / 总时长 {{ totalTime }}
  </div>
</div>
